mapper.select:
SELECT id, `year_month`, supplier_name, department, dimension_group, dimension_score, sub_scores, exception_reason, status, file_name, is_deleted, create_name, create_id, create_date, update_name, update_id, update_date FROM sp_department_score WHERE is_deleted = 0
AND `year_month` = #{yearMonth}
AND supplier_name LIKE CONCAT('%', #{supplierName}, '%')
AND department = #{department}
ORDER BY `year_month` DESC, create_date DESC

mapper.update:
UPDATE sp_department_score
`year_month` = #{yearMonth}, supplier_name = #{supplierName}, department = #{department}, dimension_group = #{dimensionGroup}, dimension_score = #{dimensionScore}, sub_scores = #{subScores}, exception_reason = #{exceptionReason}, status = #{status}, file_name = #{fileName}, update_name = #{updateName}, update_id = #{updateId},
WHERE id = #{id}
